71	        deptId: emptyToNull(data.deptId),
72	        iconColor: data.iconColor,
73	        readmeMd: emptyToNull(data.readmeMd ?? ""),
74	        permissions: data.permissions ?? {},
75	        publisherUserId: userId,
76	        ownerOrgId: DEFAULT_ORG_ID,
77	        visibility: "draft",
78	      })
79	      await tx.insert(extensionVersions).values({
80	        id: versionId,
81	        extensionId,
82	        version: data.version,
83	        status: "pending",
84	        sourceMethod: data.sourceMethod,
85	      })
86	      if (data.tagIds.length > 0) {
87	        await tx.insert(extensionTags).values(
88	          data.tagIds.map((tagId) => ({ extensionId, tagId })),
89	        )
90	      }
91	    })
92	  } catch (err) {
93	    console.error("[publish] createDraftExtension failed", err)
94	    const message = err instanceof Error ? err.message : String(err)
95	    if (message.includes("extensions_slug_unique") || message.includes("duplicate key")) {
96	      return { ok: false, error: "slug_taken" }
97	    }
98	    return { ok: false, error: "db_error", detail: message }
99	  }
100	  return { ok: true, extensionId, versionId }
101	}
