107	/**
108	 * Update an existing draft extension. Slug and version are immutable once
109	 * the draft is created (the upload pipeline keys off them), so this only
110	 * touches the mutable wizard fields. tagIds are diff-replaced.
111	 */
112	export async function updateDraftExtension(
113	  userId: string,
114	  extensionId: string,
115	  raw: ManifestFormValues,
116	): Promise<UpdateDraftResult> {
117	  const parsed = ManifestFormSchema.safeParse(raw)
118	  if (!parsed.success) {
119	    return {
120	      ok: false,
121	      error: "invalid_input",
122	      detail: parsed.error.issues.map((i) => i.message).join("; "),
123	    }
124	  }
125	  const data = parsed.data
126	  const cls = defaultClassification(data.category)
127	  const db = useDb()
128	
129	  const [existing] = await db
130	    .select({
131	      publisherUserId: extensions.publisherUserId,
132	      visibility: extensions.visibility,
133	      slug: extensions.slug,
134	    })
135	    .from(extensions)
136	    .where(eq(extensions.id, extensionId))
137	    .limit(1)
138	  if (!existing || existing.publisherUserId !== userId) {
139	    return { ok: false, error: "not_found" }
140	  }
141	  if (existing.visibility !== "draft") {
142	    return { ok: false, error: "not_editable" }
143	  }
144	  if (existing.slug !== data.slug) {
145	    return { ok: false, error: "slug_immutable" }
146	  }
147	
148	  const [latestVersion] = await db
149	    .select({ id: extensionVersions.id, version: extensionVersions.version })
150	    .from(extensionVersions)
151	    .where(eq(extensionVersions.extensionId, extensionId))
152	    .orderBy(desc(extensionVersions.createdAt))
153	    .limit(1)
154	  if (!latestVersion) return { ok: false, error: "not_found" }
155	  if (latestVersion.version !== data.version) {
156	    return { ok: false, error: "version_immutable" }
157	  }
158	
159	  try {
160	    await db.transaction(async (tx) => {
161	      await tx
162	        .update(extensions)
163	        .set({
164	          name: data.name,
165	          nameZh: emptyToNull(data.nameZh),
166	          tagline: data.summary,
167	          taglineZh: emptyToNull(data.taglineZh),
168	          category: data.category,
169	          funcCat: cls.funcCat,
170	          subCat: cls.subCat,
171	          scope: data.scope,
172	          deptId: emptyToNull(data.deptId),
173	          iconColor: data.iconColor,
174	          readmeMd: emptyToNull(data.readmeMd ?? ""),
175	          permissions: data.permissions ?? {},
176	        })
177	        .where(eq(extensions.id, extensionId))
178	      await tx
179	        .delete(extensionTags)
180	        .where(eq(extensionTags.extensionId, extensionId))
181	      if (data.tagIds.length > 0) {
182	        await tx.insert(extensionTags).values(
183	          data.tagIds.map((tagId) => ({ extensionId, tagId })),
184	        )
185	      }
186	    })
187	  } catch (err) {
188	    console.error("[publish] updateDraftExtension failed", err)
189	    return { ok: false, error: "db_error", detail: err instanceof Error ? err.message : String(err) }
190	  }
191	  return { ok: true, extensionId, versionId: latestVersion.id }
192	}
