211	export async function getDraftExtension(
212	  userId: string,
213	  extensionId: string,
214	): Promise<GetDraftResult> {
215	  const db = useDb()
216	  const [ext] = await db
217	    .select()
218	    .from(extensions)
219	    .where(eq(extensions.id, extensionId))
220	    .limit(1)
221	  if (!ext || ext.publisherUserId !== userId) {
222	    return { ok: false, error: "not_found" }
223	  }
224	  if (ext.visibility !== "draft") {
225	    return { ok: false, error: "not_editable" }
226	  }
227	
228	  const [version] = await db
229	    .select()
230	    .from(extensionVersions)
231	    .where(eq(extensionVersions.extensionId, extensionId))
232	    .orderBy(desc(extensionVersions.createdAt))
233	    .limit(1)
234	  if (!version) return { ok: false, error: "not_found" }
235	
236	  const tagRows = await db
237	    .select({ tagId: extensionTags.tagId })
238	    .from(extensionTags)
239	    .where(eq(extensionTags.extensionId, extensionId))
240	
241	  const formValues: ManifestFormValues = {
242	    slug: ext.slug,
243	    name: ext.name,
244	    nameZh: ext.nameZh ?? undefined,
245	    version: version.version,
246	    category: ext.category,
247	    scope: ext.scope,
248	    summary: ext.tagline ?? "",
249	    taglineZh: ext.taglineZh ?? undefined,
250	    readmeMd: ext.readmeMd ?? undefined,
251	    iconColor: (ext.iconColor as ManifestFormValues["iconColor"]) ?? "indigo",
252	    tagIds: tagRows.map((r) => r.tagId),
253	    deptId: ext.deptId ?? undefined,
254	    permissions: (ext.permissions ?? {}) as ManifestFormValues["permissions"],
255	    sourceMethod: (version.sourceMethod as ManifestFormValues["sourceMethod"]) ?? "zip",
256	  }
