321	export async function submitForReview(
322	  userId: string,
323	  versionId: string,
324	): Promise<SubmitResult> {
325	  const db = useDb()
326	  const [version] = await db
327	    .select({
328	      bundleFileId: extensionVersions.bundleFileId,
329	      publisherUserId: extensions.publisherUserId,
330	    })
331	    .from(extensionVersions)
332	    .innerJoin(extensions, eq(extensions.id, extensionVersions.extensionId))
333	    .where(eq(extensionVersions.id, versionId))
334	    .limit(1)
335	  if (!version || version.publisherUserId !== userId) {
336	    return { ok: false, error: "not_found" }
337	  }
338	  if (!version.bundleFileId) return { ok: false, error: "no_bundle" }
339	
340	  try {
341	    await submit(versionId)
342	  } catch (err) {
343	    if (err instanceof VersionStateError) {
344	      return { ok: false, error: "version_not_submittable" }
345	    }
346	    console.error("[publish] submitForReview failed", err)
347	    return { ok: false, error: "db_error" }
348	  }
349	
350	  try {
351	    const { inngest } = await import("~~/server/utils/inngest")
352	    await inngest.send({
353	      name: "extension/scan.requested",
354	      data: { versionId, fileId: version.bundleFileId },
355	    })
356	  } catch (err) {
357	    console.error("[publish] inngest.send failed", err)
358	    try {
359	      await db
360	        .update(extensionVersions)
361	        .set({ status: "pending" })
362	        .where(
363	          and(
364	            eq(extensionVersions.id, versionId),
365	            eq(extensionVersions.status, "scanning"),
366	          ),
367	        )
368	    } catch (rollbackErr) {
369	      console.error("[publish] rollback after inngest failure failed", rollbackErr)
370	    }
371	    return { ok: false, error: "scan_queue_unavailable" }
372	  }
373	  return { ok: true }
374	}
