418	export async function discardDraft(
419	  userId: string,
420	  extensionId: string,
421	): Promise<{ ok: true } | { ok: false; error: string }> {
422	  const db = useDb()
423	  const [row] = await db
424	    .select({
425	      publisherUserId: extensions.publisherUserId,
426	      visibility: extensions.visibility,
427	    })
428	    .from(extensions)
429	    .where(eq(extensions.id, extensionId))
430	    .limit(1)
431	
432	  if (!row || row.publisherUserId !== userId) {
433	    return { ok: false, error: "not_found" }
434	  }
435	  if (row.visibility !== "draft") {
436	    return { ok: false, error: "not_discardable" }
