FILE: cli/src/installers/cli.ts LINE: 23
_⚠️ Potential issue_ | _🔴 Critical_ | _⚡ Quick win_

**Validate `slug` and ZIP entry paths before filesystem writes/deletes.**

Line 10 and Line 19 currently trust path segments, so `../` or absolute paths can escape `~/.claude/cli` (same risk for Line 33 deletes). This is a path traversal vulnerability.



<details>
<summary>Suggested fix</summary>

```diff
 import { existsSync, mkdirSync, readdirSync, rmSync, statSync } from "fs";
 import { writeFile } from "fs/promises";
 import { homedir } from "os";
-import { dirname, join } from "path";
+import { dirname, join, resolve, sep } from "path";
 import { unzipSync } from "fflate";

 const CLI_DIR = join(homedir(), ".claude", "cli");
+
+function resolveInside(baseDir: string, unsafePath: string): string {
+  const resolved = resolve(baseDir, unsafePath);
+  if (!(resolved === baseDir || resolved.startsWith(baseDir + sep))) {
+    throw new Error(`Path escapes install root: ${unsafePath}`);
+  }
+  return resolved;
+}
+
+function assertValidSlug(slug: string): void {
+  if (!/^[a-z0-9][a-z0-9-]*$/.test(slug)) {
+    throw new Error("Invalid CLI slug");
+  }
+}

 export async function installCli(slug: string, zipBuffer: ArrayBuffer): Promise<string> {
-  const destDir = join(CLI_DIR, slug);
+  assertValidSlug(slug);
+  const destDir = resolveInside(CLI_DIR, slug);
   if (!existsSync(CLI_DIR)) mkdirSync(CLI_DIR, { recursive: true });
   if (existsSync(destDir)) rmSync(destDir, { recursive: true, force: true });
   mkdirSync(destDir, { recursive: true });

   const files = unzipSync(new Uint8Array(zipBuffer));
   try {
     for (const [entryPath, content] of Object.entries(files)) {
       if (entryPath.endsWith("/")) continue; // skip directory entries
-      const dest = join(destDir, entryPath);
+      const dest = resolveInside(destDir, entryPath);
       const parentDir = dirname(dest);
       if (!existsSync(parentDir)) mkdirSync(parentDir, { recursive: true });
       await writeFile(dest, content);
     }
   } catch (err) {
@@
 export async function uninstallCli(slug: string): Promise<boolean> {
-  const destDir = join(CLI_DIR, slug);
+  assertValidSlug(slug);
+  const destDir = resolveInside(CLI_DIR, slug);
   if (!existsSync(destDir)) return false;
   rmSync(destDir, { recursive: true, force: true });
   return true;
 }
```
</details>


Also applies to: 33-35

<details>
<summary>🤖 Prompt for AI Agents</summary>

```
Verify each finding against current code. Fix only still-valid issues, skip the
rest with a brief reason, keep changes minimal, and validate.

In `@cli/src/installers/cli.ts` around lines 10 - 23, Validate and sanitize the
user-provided slug and each ZIP entry path before any mkdirSync/rmSync/writeFile
calls: reject slugs that are absolute or contain ".." or path separators after
normalization, and for each entryPath compute a safe destination by joining
CLI_DIR (not just destDir) with the normalized entryPath, ensure the normalized
destination is inside the intended destDir (e.g., using path.normalize and
path.relative and confirming the relative path does not start with ".." and the
path is not absolute) before creating parent directories or writing; similarly,
before rmSync of destDir ensure the resolved path is a child of CLI_DIR to
prevent deleting outside ~/.claude/cli; update the loop around entryPath, the
destDir computation, and the rmSync usage to perform these checks and throw on
invalid paths.
```

</details>

